export function toposort<T>(nodes: T[], edges: Array<[T, T]>): T[] {
  if (nodes.length === 0) {
    return [];
  }

  const inDegree = new Map<T, number>();
  const adjacency = new Map<T, Set<T>>();
  const nodeSet = new Set(nodes);

  nodes.forEach(node => {
    inDegree.set(node, 0);
    adjacency.set(node, new Set());
  });

  edges.forEach(([from, to]) => {
    if (!nodeSet.has(from) || !nodeSet.has(to)) {
      throw new Error("Edge references non-existent node");
    }

    const neighbors = adjacency.get(from)!;
    if (!neighbors.has(to)) {
      neighbors.add(to);
      inDegree.set(to, inDegree.get(to)! + 1);
    }
  });

  const queue: T[] = [];
  inDegree.forEach((degree, node) => {
    if (degree === 0) queue.push(node);
  });

  const result: T[] = [];
  while (queue.length > 0) {
    const node = queue.shift()!;
    result.push(node);

    adjacency.get(node)!.forEach(neighbor => {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1);
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor);
      }
    });
  }

  if (result.length !== nodes.length) {
    throw new Error("Cycle detected in graph");
  }

  return result;
}
```

This uses Kahn's algorithm with in-degree tracking. Initialize all nodes with zero in-degree, then process edges to increment in-degrees for destination nodes. Start with all zero in-degree nodes in a queue, process them one by one, decrementing neighbors' in-degrees. If the final result doesn't include all nodes, a cycle exists and we throw an error.

